 32→    if(typeof value === 'boolean') return value;
 33→    if(typeof value === 'string'){
 34→        const normalized = value.trim().toLowerCase();
 35→        if(normalized === 'true') return true;
 36→        if(normalized === 'false') return false;
 37→    }
