343→        mutationFn: (data) => updatePrivacy(session?.access_token, data),
344→        onMutate: async(data) => {
345→            await queryClient.cancelQueries(['userJournals', session?.user?.id])
346→            const previousData = queryClient.getQueryData(['userJournals', session?.user?.id])
347→
348→            const journalId = data.get('journalId')
349→            const privacy = data.get('privacy');
350→
351→            // console.log(privacy)
352→
353→            queryClient.setQueryData(['userJournals', session?.user?.id], (old) => {
354→                if(!old) return old;
355→
356→                return{
357→                    ...old,
358→                    pages: old.pages.map((page) => ({
359→                        ...page,
360→                        data: page.data.map((journal) => {
361→                            if(journal.id !== journalId) return journal;
362→
363→                            return{
364→                                ...journal,
365→                                privacy: privacy
366→                            }
367→                        })
368→                    }))
369→                }
370→            })
371→            console.log(previousData)
372→            return {previousData};
373→            
374→        },
375→        onError: (err, data, context) =>{
376→            queryClient.setQueryData(['userJournals', session?.user?.id], context.previousData)
377→        },
378→        onSuccess: (data) => console.log(data),
379→        retry: 1,
380→    })
381→}
382→export const useUpdateCollectionPrivacyMutation = (session) => {
383→    const queryClient= useQueryClient();
384→    return useMutation({
385→        mutationFn: (data) => updateCollectionPrivacy(data, session?.access_token),
386→        onMutate: async(data) =>{
387→            const userId = data.get('userId')
388→            const collectionId = data.get('collectionId')
389→            await queryClient.cancelQueries(['getCollections', userId])
390→
391→            const previousData = queryClient.getQueryData(['getCollections', userId])
392→            const isPublic = data.get('isPublic');
393→
394→            queryClient.setQueryData(['getCollections', userId], (old) => {
395→                if(!old) return old;
396→
397→                return{
398→                    ...old,
399→                    pages: old.pages.map((page) =>({
400→                        ...page,
401→                        data: page.data.map((collection) => {
402→                            if(collection.id !== collectionId) return collection;
403→
404→                            return {
405→                                ...collection,
406→                                is_public: isPublic
407→                            }
408→                        })
409→                    }))
410→                }
411→            })
412→            return {previousData};
413→        },
414→        onError: (err, data, context) =>{
415→            queryClient.setQueryData(['getCollections', session?.user?.id], context.previousData)
416→        },
417→        retry: 1,
418→        onSucces: (data) => console.log(data)
419→    })
420→}
421→
422→export const useRespondConstellationMutation = (session) => {
423→    const queryClient = useQueryClient();
424→    return useMutation({
425→        mutationFn: (data) => respondConstellation(session?.access_token, data?.constellationId, data?.accept),
426→        onMutate: async (data) => {
427→            await queryClient.cancelQueries(['getNotifications']);
428→            const previousData = queryClient.getQueryData(['getNotifications']);
429→            queryClient.setQueryData(['getNotifications'], (old) => {
430→                if (!old || !Array.isArray(old.pages)) return old;
431→                return {
432→                    ...old,
433→                    pages: old.pages.map((page) => ({
434→                        ...page,
435→                        data: Array.isArray(page?.data) ? page.data.map((notif) => {
436→                            if (notif.constellation_id === data.constellationId) {
437→                                return { ...notif, constellations: { status: data.accept ? 'accepted' : 'declined' } };
438→                            }
439→                            return notif;
440→                        }) : page?.data,
441→                    })),
442→                };
443→            });
444→            return { previousData };
445→        },
446→        onError: (err, data, context) => {
447→            if (context?.previousData) {
448→                queryClient.setQueryData(['getNotifications'], context.previousData);
449→            }
450→        },
451→        onSettled: () => {
452→            queryClient.invalidateQueries(['getNotifications']);
453→        }
454→    });
455→}
456→
457→export const useRepostMutation = (session) => {
458→    const queryClient = useQueryClient();
459→    return useMutation({
460→        mutationFn: (data) => createRepost(session?.access_token, data),
461→        onSuccess: () => {
462→            queryClient.invalidateQueries({ queryKey: ['journals'] });
463→            queryClient.invalidateQueries({ queryKey: ['userJournals'] });
464→        }
465→    });
466→}
