    z-index: 100;
}

.reaction-option {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border: none;
    background: transparent;
    border-radius: 50%;
    cursor: pointer;
    font-size: 1.4rem;
    transition: background 0.15s ease;
}

.reaction-option:hover {
    background: var(--bg-hover);
}

.reaction-option--active {
    background: var(--bg-hover);
    box-shadow: 0 0 0 2px var(--accent-purple);
}

.reaction-button-container {
    position: relative;
    display: inline-flex;
}

.reaction-active-emoji {
    font-size: 1.1rem;
    line-height: 1;
}

.reaction-summary {
    display: flex;
    gap: 8px;
    padding: 4px 0;
    flex-wrap: wrap;
}

.reaction-summary-item {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    border-radius: 12px;
    background: var(--bg-hover);
    font-size: 0.85rem;
    cursor: default;
}

